export function getEmhGraphqlQuery(country: string, product: string, vehicleCategory: string = "PASSENGER-CARS"): string {
  const key = `${country.toUpperCase()}-${product.toUpperCase()}-${vehicleCategory.toUpperCase()}`;
  return (
    GET_SEARCH_RESULTS_COUNTRY_QUERIES[key] ??
    (product.toUpperCase() === "UCOS"
      ? GET_SEARCH_RESULTS_COUNTRY_QUERIES["TR-UCOS-PASSENGER-CARS"]
      : GET_SEARCH_RESULTS_COUNTRY_QUERIES["TR-NCOS-PASSENGER-CARS"])
  );
}

